40: const commentParser = new ConfigCommentParser();
41: const configCommentStart =
42: 	/<!--\s*(eslint(?:-enable|-disable(?:(?:-next)?-line)?))(?:\s|-->)/u;
43: const htmlComment = /<!--(.*?)-->/gsu;
