45: /**
46:  * Represents an inline config comment in the source code.
47:  */
48: class InlineConfigComment {
49: 	/**
50: 	 * The comment text.
51: 	 * @type {string}
52: 	 */
53: 	value;
54: 
55: 	/**
56: 	 * The position of the comment in the source code.
57: 	 * @type {SourceLocation}
58: 	 */
59: 	position;
60: 
61: 	/**
62: 	 * Creates a new instance.
63: 	 * @param {Object} options The options for the instance.
64: 	 * @param {string} options.value The comment text.
65: 	 * @param {SourceLocation} options.position The position of the comment in the source code.
66: 	 */
67: 	constructor({ value, position }) {
68: 		this.value = value.trim();
69: 		this.position = position;
70: 	}
71: }
