73: /**
74:  * Extracts inline configuration comments from an HTML node.
75:  * @param {HTMLNode} node The HTML node to extract comments from.
76:  * @returns {Array<InlineConfigComment>} The inline configuration comments found in the node.
77:  */
78: function extractInlineConfigCommentsFromHTML(node) {
79: 	if (!configCommentStart.test(node.value)) {
80: 		return [];
81: 	}
82: 	const comments = [];
83: 
84: 	let match;
85: 
86: 	while ((match = htmlComment.exec(node.value))) {
87: 		if (configCommentStart.test(match[0])) {
88: 			const comment = match[0];
89: 
90: 			// calculate location of the comment inside the node
91: 			const start = {
92: 				...node.position.start,
93: 			};
94: 
95: 			const end = {
96: 				...node.position.start,
97: 			};
98: 
99: 			const {
100: 				lineOffset: startLineOffset,
101: 				columnOffset: startColumnOffset,
102: 			} = findOffsets(node.value, match.index);
103: 
104: 			start.line += startLineOffset;
105: 			start.column += startColumnOffset;
106: 			start.offset += match.index;
107: 
108: 			const commentLineCount = comment.split("\n").length - 1;
109: 
110: 			end.line = start.line + commentLineCount;
111: 			end.column =
112: 				commentLineCount === 0
113: 					? start.column + comment.length
114: 					: comment.length - comment.lastIndexOf("\n");
115: 			end.offset = start.offset + comment.length;
116: 
117: 			comments.push(
118: 				new InlineConfigComment({
119: 					value: match[1].trim(),
120: 					position: {
121: 						start,
122: 						end,
123: 					},
124: 				}),
125: 			);
126: 		}
127: 	}
128: 
129: 	return comments;
130: }
