145: 
146: 	/**
147: 	 * Cache of parent nodes.
148: 	 * @type {WeakMap<MarkdownNode, MarkdownNode>}
149: 	 */
150: 	#parents = new WeakMap();
151: 
152: 	/**
153: 	 * Collection of HTML nodes. Used to find directive comments.
154: 	 * @type {Array<HTMLNode>}
155: 	 */
156: 	#htmlNodes = [];
157: 
158: 	/**
159: 	 * Collection of inline configuration comments.
160: 	 * @type {Array<InlineConfigComment>}
161: 	 */
162: 	#inlineConfigComments;
163: 
164: 	/**
165: 	 * The AST of the source code.
166: 	 * @type {RootNode}
167: 	 */
168: 	ast = undefined;
169: 
170: 	/**
171: 	 * Creates a new instance.
172: 	 * @param {Object} options The options for the instance.
173: 	 * @param {string} options.text The source code text.
174: 	 * @param {RootNode} options.ast The root AST node.
175: 	 */
176: 	constructor({ text, ast }) {
177: 		super({ ast, text });
178: 		this.ast = ast;
179: 
180: 		// need to traverse the source code to get the inline config nodes
181: 		this.traverse();
182: 	}
183: 
184: 	/**
185: 	 * Returns the parent of the given node.
186: 	 * @param {MarkdownNode} node The node to get the parent of.
187: 	 * @returns {MarkdownNode|undefined} The parent of the node.
188: 	 */
189: 	getParent(node) {
190: 		return this.#parents.get(node);
191: 	}
192: 
193: 	/**
194: 	 * Returns an array of all inline configuration nodes found in the
195: 	 * source code.
196: 	 * @returns {Array<InlineConfigComment>} An array of all inline configuration nodes.
197: 	 */
198: 	getInlineConfigNodes() {
199: 		if (!this.#inlineConfigComments) {
200: 			this.#inlineConfigComments = this.#htmlNodes.flatMap(
201: 				extractInlineConfigCommentsFromHTML,
202: 			);
203: 		}
204: 
205: 		return this.#inlineConfigComments;
206: 	}
207: 
208: 	/**
209: 	 * Returns an all directive nodes that enable or disable rules along with any problems
210: 	 * encountered while parsing the directives.
211: 	 * @returns {{problems:Array<FileProblem>,directives:Array<Directive>}} Information
212: 	 *      that ESLint needs to further process the directives.
213: 	 */
214: 	getDisableDirectives() {
215: 		const problems = [];
216: 		const directives = [];
217: 
218: 		this.getInlineConfigNodes().forEach(comment => {
219: 			// Step 1: Parse the directive
220: 			const {
221: 				label,
222: 				value,
223: 				justification: justificationPart,
224: 			} = commentParser.parseDirective(comment.value);
225: 
226: 			// Step 2: Validate the directive does not span multiple lines
227: 			if (
228: 				label === "eslint-disable-line" &&
229: 				comment.position.start.line !== comment.position.end.line
230: 			) {
231: 				const message = `${label} comment should not span multiple lines.`;
232: 
233: 				problems.push({
234: 					ruleId: null,
235: 					message,
236: 					loc: comment.position,
237: 				});
238: 				return;
239: 			}
240: 
241: 			// Step 3: Extract the directive value and create the Directive object
242: 			switch (label) {
243: 				case "eslint-disable":
244: 				case "eslint-enable":
245: 				case "eslint-disable-next-line":
246: 				case "eslint-disable-line": {
247: 					const directiveType = label.slice("eslint-".length);
248: 
249: 					directives.push(
250: 						new Directive({
251: 							type: /** @type {DirectiveType} */ (directiveType),
252: 							node: comment,
253: 							value,
254: 							justification: justificationPart,
255: 						}),
256: 					);
257: 				}
258: 
259: 				// no default
260: 			}
261: 		});
262: 
263: 		return { problems, directives };
264: 	}
265: 
266: 	/**
267: 	 * Traverse the source code and return the steps that were taken.
268: 	 * @returns {Iterable<TraversalStep>} The steps that were taken while traversing the source code.
269: 	 */
270: 	traverse() {
271: 		// Because the AST doesn't mutate, we can cache the steps
272: 		if (this.#steps) {
273: 			return this.#steps.values();
274: 		}
275: 
276: 		/** @type {Array<VisitNodeStep>} */
277: 		const steps = (this.#steps = []);
278: 
279: 		const visit = (node, parent) => {
280: 			// first set the parent
281: 			this.#parents.set(node, parent);
282: 
283: 			// then add the step
284: 			steps.push(
285: 				new VisitNodeStep({
286: 					target: node,
287: 					phase: 1,
288: 					args: [node, parent],
289: 				}),
290: 			);
291: 
292: 			// save HTML nodes
293: 			if (node.type === "html") {
294: 				this.#htmlNodes.push(node);
295: 			}
296: 
297: 			// then visit the children
298: 			if (node.children) {
299: 				node.children.forEach(child => {
300: 					visit(child, node);
301: 				});
302: 			}
303: 
304: 			// then add the exit step
305: 			steps.push(
306: 				new VisitNodeStep({
307: 					target: node,
308: 					phase: 2,
309: 					args: [node, parent],
310: 				}),
311: 			);
312: 		};
313: 
314: 		visit(this.ast);
315: 
316: 		return steps.values();
317: 	}
318: }
